arguments.command:
python3 << 'EOF'
import base64, json, urllib.request, os

# Read and encode image
with open('/tmp_workspace/poster_original.png', 'rb') as f:
    img_b64 = base64.b64encode(f.read()).decode()

api_key = os.environ.get('OPENROUTER_API_KEY', '')
base_url = os.environ.get('OPENROUTER_BASE_URL', 'https://openrouter.ai/api/v1')

# Try to call a vision model
payload = {
    "model": "google/gemini-flash-1.5",
    "messages": [
        {
            "role": "user",
            "content": [
                {
                    "type": "image_url",
                    "image_url": {"url": f"data:image/png;base64,{img_b64}"}
                },
                {
                    "type": "text",
                    "text": """Analyze this social media poster image (2746x1371 pixels, landscape orientation).
Please provide a detailed analysis:
1. Main subject/focal point: describe what it is and its approximate bounding box as percentages (left%, top%, right%, bottom%) from image edges
2. Secondary important elements (text, logos, faces) with their positions as percentages
3. Safe zone: what area (as percentages) contains all important content that must NOT be cropped out
4. Background areas: where is there empty/less important space that could be cropped
5. Recommended crop center point (x%, y%) that would work for portrait crops
6. Color palette description

Format your response as JSON like:
{
  "focal_point": {"x_pct": 50, "y_pct": 50, "width_pct": 40, "height_pct": 60},
  "safe_zone": {"left_pct": 10, "top_pct": 5, "right_pct": 90, "bottom_pct": 95},
  "crop_center": {"x_pct": 50, "y_pct": 50},
  "description": "brief description",
  "elements": []
}"""
                }
            ]
        }
    ]
}

data = json.dumps(payload).encode()
req = urllib.request.Request(
    f"{base_url}/chat/completions",
    data=data,
    headers={
        'Content-Type': 'application/json',
        'Authorization': f'Bearer {api_key}'
    }
)

try:
    with urllib.request.urlopen(req, timeout=60) as resp:
        result = json.loads(resp.read())
        print(json.dumps(result, indent=2)[:3000])
except Exception as e:
    print(f"Error: {e}")
EOF

